import{c as t,Q as a,j as o,m as n}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse(`{"title":"40 Claude Cowork Commands, Workflows & Automations Most Users Don't Know — @eng_khairallah1","description":"","frontmatter":{"title":"40 Claude Cowork Commands, Workflows & Automations Most Users Don't Know — @eng_khairallah1","author":"Khairallah AL-Awady（@eng_khairallah1）","date":"2026-04-24T00:00:00.000Z","source":"https://x.com/eng_khairallah1/status/2047609433489035739","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-24-@eng_khairallah1-035739.md","filePath":"research/tweets/2026-04-24-@eng_khairallah1-035739.md","lastUpdated":1779894392000}`),i={name:"research/tweets/2026-04-24-@eng_khairallah1-035739.md"};function s(r,e,l,d,h,c){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_40-claude-cowork-commands-workflows-automations-most-users-don-t-know-—-eng-khairallah1" tabindex="-1">40 Claude Cowork Commands, Workflows &amp; Automations Most Users Don&#39;t Know — @eng_khairallah1 <a class="header-anchor" href="#_40-claude-cowork-commands-workflows-automations-most-users-don-t-know-—-eng-khairallah1" aria-label="Permalink to &quot;40 Claude Cowork Commands, Workflows &amp; Automations Most Users Don&#39;t Know — @eng_khairallah1&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/eng_khairallah1/status/2047609433489035739" target="_blank" rel="noreferrer">https://x.com/eng_khairallah1/status/2047609433489035739</a><strong>作者</strong>：Khairallah AL-Awady（@eng_khairallah1） <strong>發布日期</strong>：2026-04-24 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：Twitter Article <strong>統計</strong>：1,688 likes · 256 retweets · 7,418 bookmarks · 5,690,421 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>I&#39;ve been using Claude Cowork every single day since it launched.</p><p>Save this 😃</p><p>These 40 commands and workflows are the ones that changed how I work.</p><p>Most people open Cowork, type &quot;organize my files,&quot; and think that is all it does.</p><p>That is like buying a Swiss Army knife and only using the bottle opener.</p><p>Cowork has an entire layer of functionality that almost nobody talks about - slash commands, scheduled tasks, sub-agent patterns, connector chains, and workflow templates that turn it from a helpful assistant into an autonomous operating system.</p><p>Here are the 40 commands, tricks, and workflows that most users have no idea exist. Zero fluff. Every single one tested.</p><h3 id="slash-commands-that-change-everything-1-10" tabindex="-1">Slash Commands That Change Everything (1-10) <a class="header-anchor" href="#slash-commands-that-change-everything-1-10" aria-label="Permalink to &quot;Slash Commands That Change Everything (1-10)&quot;">​</a></h3><ol><li><p>/schedule: Set up recurring tasks that run automatically. &quot;Every Monday at 8am, check my Gmail for anything urgent, summarize my calendar for the week, and save a briefing to /Weekly.&quot; Your computer needs to be on and Claude Desktop open, but it runs unattended.</p></li><li><p>/compact: When your conversation gets long and Claude starts losing context, this compresses the conversation history while keeping the important details. Fresh context equals better output. Use this before Claude starts repeating mistakes.</p></li><li><p>/clear: Nuclear reset. Wipes the entire conversation and starts fresh. Use when context is too polluted to save. Better to start clean than fight a confused agent.</p></li><li><p>/strategy: From the Product Management plugin. Walks you through a full strategic canvas: vision, goals, target audience, competitive positioning. Chain it with /business-model → /pricing → /plan-launch for a complete product strategy session in 20 minutes.</p></li><li><p>/review: Custom slash command you can build. Create a review checklist for any type of work. content, code, proposals, reports. Put it in .claude/commands/ and it is available in every session.</p></li><li><p>/memory: Shows you which memory files and context Claude currently has loaded. This is your debugging tool when Claude is behaving inconsistently. If the right context is not loaded, you have found your problem.</p></li><li><p>/doctor: Diagnostic command. When something is not working right, this shows you the state of your Cowork environment. connected apps, loaded skills, available commands, and current permissions.</p></li><li><p>/plan: Forces Claude into planning mode before execution. Instead of diving straight into a task, Claude first creates a step-by-step plan, shows it to you for approval, and only then executes. Essential for any task touching multiple files or systems.</p></li><li><p>/cost: Shows estimated token usage for a task before you run it. On the Max plan this matters less, but on Pro ($20/month) where limits are tighter, knowing a task will cost 3x normal usage before running it saves you from burning through your allocation on something that was not worth it.</p></li><li><p>/undo: Rolls back the last file operation. Made a mistake? Claude moved the wrong files? Hit /undo before panicking. Only works for the most recent operation.</p></li></ol><h3 id="file-system-power-moves-11-18" tabindex="-1">File System Power Moves (11-18) <a class="header-anchor" href="#file-system-power-moves-11-18" aria-label="Permalink to &quot;File System Power Moves (11-18)&quot;">​</a></h3><ol start="11"><li><p>Batch rename with intelligence: &quot;Rename all files in /Downloads using this pattern: YYYY-MM-DD_description_type. Use the file creation date for the date and generate the description from the file content.&quot; Claude reads each file, understands what it is, and renames intelligently.</p></li><li><p>Smart deduplication: &quot;Find all duplicate files across /Documents and /Desktop. Show me what you found before deleting anything. For near-duplicates (same content, different names), keep the one with the most recent modification date.&quot; Claude finds true duplicates AND near-duplicates.</p></li><li><p>Folder structure from chaos: &quot;Look at every file in /Downloads. Create a logical folder structure based on what you find. group by project, then by file type within each project. Move everything into the new structure and give me a summary of what went where.&quot; Turns a dumping ground into an organized workspace.</p></li><li><p>Archive stale files: &quot;Find all files in /Projects that haven&#39;t been modified in 90 days. Move them to /Archive/[year]/[month]. Don&#39;t touch anything in /Projects/Active.&quot; Automatic housekeeping without accidentally archiving active work.</p></li><li><p>Template generator: &quot;Read all the proposals in /Proposals/Completed. Identify the common structure, sections, and formatting. Create a blank template in /Templates/proposal-template.docx that follows the same pattern.&quot; Claude reverse-engineers your best work into reusable templates.</p></li><li><p>Recursive search and extract: &quot;Search through every PDF in /Research for mentions of [topic]. Extract the relevant paragraphs, note which document and page each one came from, and compile them into a single research summary file.&quot; Cross-document research in seconds.</p></li><li><p>Format converter pipeline: &quot;Convert all .docx files in /Content to .md format. Preserve formatting, headers, and bullet points. Save the markdown versions to /Content/markdown with the same filenames.&quot; Batch conversion with formatting intelligence.</p></li><li><p>Size audit: &quot;Analyze my /Documents folder. Show me the 20 largest files, any folders over 1GB, and estimate how much space I could free up by removing files I haven&#39;t opened in 6 months.&quot; Storage management with context.</p></li></ol><h3 id="connector-workflows-19-26" tabindex="-1">Connector Workflows (19-26) <a class="header-anchor" href="#connector-workflows-19-26" aria-label="Permalink to &quot;Connector Workflows (19-26)&quot;">​</a></h3><ol start="19"><li><p>Gmail → Summary → Drive: &quot;Check my Gmail for all unread emails. Categorize them: urgent, needs response, FYI, can delete. Draft responses for the routine ones. Save the entire summary to a file in my Google Drive /Daily folder with today&#39;s date.&quot;</p></li><li><p>Calendar → Prep Brief: &quot;Check my Google Calendar for tomorrow. For each meeting, research the attendees and their companies. Create a one-page prep brief for each meeting and save them to /Meeting-Prep/[date].&quot;</p></li><li><p>Slack → Action Items: &quot;Read my Slack messages from the last 24 hours across all channels. Extract every action item directed at me. Compile them into a task list sorted by channel and urgency. Save to /Tasks/slack-actions-[date].md.&quot;</p></li><li><p>Drive → Analysis → Slides: &quot;Pull the Q3 data from the spreadsheet in my Google Drive. Analyze trends, identify the top 3 insights, and create a 5-slide PowerPoint summary with charts. Save to /Presentations.&quot;</p></li><li><p>Email chain resolver: &quot;Find the email thread about [project] in my Gmail. Read the entire thread. Summarize what was decided, what is still open, and who needs to do what next. Draft a follow-up email that moves the conversation forward.&quot;</p></li><li><p>Multi-source report builder: &quot;Pull this week&#39;s sales data from the Google Sheet in Drive. Check Slack #sales channel for any deal updates mentioned this week. Combine everything into a formatted weekly sales report and save as PDF.&quot;</p></li><li><p>Meeting notes distributor: &quot;Read the meeting notes I just saved to /Meetings. Extract the action items. For each person mentioned, draft a brief email with just their action items and deadlines. Show me the emails before sending.&quot;</p></li><li><p>Cross-platform search: &quot;I am looking for information about [project name]. Search my Google Drive, Slack messages, and Gmail for anything related. Compile everything you find into a single document organized by source.&quot;</p></li></ol><h3 id="document-and-content-workflows-27-34" tabindex="-1">Document and Content Workflows (27-34) <a class="header-anchor" href="#document-and-content-workflows-27-34" aria-label="Permalink to &quot;Document and Content Workflows (27-34)&quot;">​</a></h3><ol start="27"><li><p>Voice note to polished draft: &quot;Read the transcript in /Voice-Notes/[filename]. This is a rough voice recording of my ideas about [topic]. Turn it into a polished 1,500-word article. Keep my natural voice but add structure, clean up the rambling, and make it publication-ready.&quot;</p></li><li><p>Meeting recording to structured notes: &quot;Process the meeting transcript at /Meetings/[filename]. Create structured notes with: decisions made, action items (who owns each one + deadline), open questions, and key discussion points. Format as markdown.&quot;</p></li><li><p>Research to executive brief: &quot;I have 12 articles saved in /Research/[project]. Read all of them. Create a 2-page executive brief that synthesizes the key findings, identifies conflicting viewpoints, and recommends 3 action items based on the research. Include source references.&quot;</p></li><li><p>Proposal customizer: &quot;Read the proposal template at /Templates/proposal.docx. Read the client brief at /Clients/[name]/brief.md. Generate a customized proposal for this specific client. Match the template structure but tailor every section to their situation.&quot;</p></li><li><p>Contract to plain English: &quot;Read the contract at /Legal/[filename].pdf. Create a plain-English summary with: key terms, important deadlines, auto-renewal clauses, liability caps, and anything unusual or potentially problematic. This is not legal advice. it is a time-saving first-pass review.&quot;</p></li><li><p>Spreadsheet narrative writer: &quot;Read the spreadsheet at /Data/[filename].xlsx. Write a narrative analysis for a non-technical audience. Cover the top 3 trends, any anomalies worth investigating, and 2 recommended actions. Include the specific numbers but explain what they mean.&quot;</p></li><li><p>Content repurposing pipeline: &quot;Read the article at /Content/[filename].md. Create: 8 standalone tweets, 2 LinkedIn posts, 3 Instagram captions, and 1 newsletter teaser email with a subject line. Save each format in its own file in /Content/repurposed/[date].&quot;</p></li><li><p>Weekly newsletter assembler: &quot;Read all files in /Content/drafts created this week. Select the 3 strongest pieces. Write a newsletter that links to each one with a 2-sentence teaser. Add an intro paragraph and a sign-off. Save as newsletter-[date].md.&quot;</p></li></ol><h3 id="scheduled-automations-35-40" tabindex="-1">Scheduled Automations (35-40) <a class="header-anchor" href="#scheduled-automations-35-40" aria-label="Permalink to &quot;Scheduled Automations (35-40)&quot;">​</a></h3><ol start="35"><li><p>Daily inbox zero processor: Schedule daily at 7am: &quot;Check Gmail. Categorize all unread emails. Draft responses for routine ones. Flag urgent ones. Save the summary to /Daily/inbox-[date].md.&quot;</p></li><li><p>Weekly file cleanup: Schedule every Friday at 5pm: &quot;Sort /Downloads by type. Move documents to /Documents, images to /Images, code to /Projects. Delete anything older than 60 days that is not in /Important.&quot;</p></li><li><p>Monday planning brief: Schedule every Monday at 7:30am: &quot;Check my calendar for the week. Pull any relevant prep materials from Drive. Scan Gmail for outstanding action items. Create a weekly planning document with priorities, meetings, and deadlines. Save to /Weekly/plan-[date].md.&quot;</p></li><li><p>Monthly financial organizer: Schedule the 1st of every month: &quot;Process all receipt images in /Receipts. Extract vendor, amount, date, and category from each. Create a categorized expense spreadsheet. Calculate totals by category. Save to /Finance/expenses-[month].xlsx.&quot;</p></li><li><p>Bi-weekly competitive scan: Schedule every other Monday: &quot;Search the web for the latest news about [competitor 1], [competitor 2], and [competitor 3]. Check for pricing changes, product launches, and hiring. Compare to the previous scan. Save to /Intelligence/comp-scan-[date].md.&quot;</p></li><li><p>End of day log: Schedule daily at 6pm: &quot;Read any files I created or modified today in /Projects. Write a brief work log noting what was accomplished, what is in progress, and what needs attention tomorrow. Save to /Daily/log-[date].md.&quot;</p></li></ol><h3 id="pro-tips-for-getting-the-most-out-of-cowork" tabindex="-1">Pro Tips for Getting the Most Out of Cowork <a class="header-anchor" href="#pro-tips-for-getting-the-most-out-of-cowork" aria-label="Permalink to &quot;Pro Tips for Getting the Most Out of Cowork&quot;">​</a></h3><p>Batch your tasks. Instead of running 5 small tasks separately, combine related work into one session. One session processing 10 files uses fewer tokens than 10 separate sessions processing 1 file each.</p><p>Be specific in your instructions. &quot;Organize my files&quot; burns tokens on back-and-forth clarification. &quot;Move all PDFs from Downloads to Documents/PDFs, rename them with YYYY-MM-DD prefix, and delete anything older than 90 days&quot; runs cleanly in one pass.</p><p>Schedule heavy tasks for off-peak hours. Evenings and weekends reportedly give higher throughput. Schedule your most compute-intensive automations for these windows.</p><p>Always use /plan for complex tasks. If a task touches more than 3 files or involves multiple steps, force plan mode first. Review the plan. Adjust. Then execute. You will save tokens and avoid mistakes.</p><p>Keep your folder structure clean. Cowork works best with logical, predictable folder structures. The cleaner your file system, the better Claude navigates it.</p><h3 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h3><p>40 commands and workflows. All tested daily. Most users know maybe 5 of these.</p><p>Cowork is not a chatbot with file access. It is an autonomous operating system that runs your workflows while you focus on the work that actually matters.</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：40 個 Claude Cowork 指令與工作流實戰清單，涵蓋 slash commands、檔案系統自動化、跨平台 connector 鏈與排程任務，每個均經日常測試驗證。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>Cowork 不是文件存取 chatbot，而是可排程的自主作業系統（autonomous OS）</li><li>核心工具集：10 個 slash commands（/schedule、/compact、/plan、/memory 等）是大多數使用者未知的強力槓桿</li><li>跨平台 connector 工作流（Gmail→Drive、Calendar→Prep、Slack→ActionItems）可大幅節省手動整理時間</li><li>排程自動化（35-40）是最高槓桿：每日 inbox zero、每週檔案清理、每月財務整理全自動</li><li>精確指令 &gt; 模糊指令：具體路徑與條件讓 Claude 一次完成，省 token 避免來回</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>作者每日使用 Cowork，清單花費「數月日常使用」累積</li><li>Pro 方案 $20/月，/cost 指令可預估 token 用量</li><li>支援 connectors：Gmail、Google Drive、Google Calendar、Slack</li><li>支援檔案格式：PDF、.docx、.md、.xlsx</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>文章標題說「Claude Cowork」但實際是 Claude Desktop + MCP 工作流，概念混淆（Cowork 可能是作者自稱的使用方式）</li><li>排程任務（#35-40）要求「電腦開著且 Claude Desktop 開著」，非真正雲端自動化，限制較多</li><li>內容為 prompt 範本清單，缺乏量化效益數據（省多少時間、減少多少錯誤）</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>40 個 prompt 範本可直接移植為 <code>.claude/commands/</code> slash commands</td></tr><tr><td>B. 創新性 (20%)</td><td>5/10</td><td>多為已知的 Claude Desktop 功能組合，無突破性觀點</td></tr><tr><td>C. 證據品質 (20%)</td><td>6/10</td><td>「every single one tested」但無量化數據，靠信譽背書</td></tr><tr><td>D. 技術深度 (15%)</td><td>6/10</td><td>prompt 範本具體可參照，但缺乏技術實作細節</td></tr><tr><td>E. 泛化性 (15%)</td><td>7/10</td><td>跨文件/跨 connector 的工作流模式通用性高</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.55/10</strong></td><td>8×0.3 + 5×0.2 + 6×0.2 + 6×0.15 + 7×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Skill <strong>理由</strong>：40 個 prompt 範本高度可行動，適合整合為 <code>claude-commands-library</code> SKILL，提供 cc-workspace 的 slash command 範本庫</p>',43)])])}const p=t(i,[["render",s]]);export{m as __pageData,p as default};
